## 1. Player Class (`src/game.js`)

```javascript
class Player {
  constructor(name, health) {
    this.name = name;
    this.health = health;
  }

  getPlayerStats() {
    return {
      name: this.name,
      health: this.health,
    };
  }

  takeDamage(amount) {
    this.health -= amount;
    if (this.health <= 0) {
      this.isAlive = false;
    }
  }
}
```

---

## 2. Performance Tracker (`src/metrics/PerformanceTracker.ts`)

```typescript
export class PerformanceTracker {
  private metrics: Map<string, number>;
  private startTime: number;

  constructor() {
    this.metrics = new Map();
    this.startTime = Date.now();
  }

  public record(key: string, value: number): void {
    this.metrics.set(key, value);
  }

  public track(key: string): number {
    return this.metrics.get(key) || 0;
  }

  public getAllMetrics(): Map<string, number> {
    return new Map(this.metrics);
  }
}
```

---

## 3. Metrics Collector (`src/metrics/MetricsCollector.ts`)

```typescript
export class MetricsCollector {
  private records: MetricRecord[] = [];
  private flushInterval: number = 60000;

  record(metric: MetricRecord): void {
    this.records.push(metric);
    if (this.records.length >= this.batchSize) {
      this.flush();
    }
  }

  async fetch(key: string): Promise<MetricRecord[]> {
    // Returns metrics within a time window
    const now = Date.now();
    return this.records.filter(r => r.timestamp > now - this.window);
  }

  private async flush(): Promise<void> {
    if (this.records.length === 0) return;
    const records = this.records.splice(0);
    await this.storage.batchStore(records);
  }
}
```

---

## 4. Engine (`src/engine/Engine.ts`)

```typescript
export class Engine {
  private collector: MetricsCollector;
  private isRunning: boolean = false;

  public recordStatistic(stat: StatRecord): void {
    this.collector.record(stat);
    this.emit('statRecorded', stat);
  }
}
```

---

## 5. Reporter (`src/reporting/Reporter.ts`)

```typescript
export class Reporter {
  public getPerformanceReport(startDate: Date, endDate: Date): PerformanceReport {
    const metrics = this.aggregateMetrics(startDate, endDate);
    return this.formatReport(metrics);
  }

  private aggregateMetrics(startDate: Date, endDate: Date): AggregatedData {
    const sources = this.getDataSources();
    return this.mergeMetrics(sources, startDate, endDate);
  }

  private getDataSources(): DataSource[] { ... }

  public mergeMetrics(data: Metric[]): MergedResult { ... }

  public formatReport(results: MergedResult): string { ... }
}
```

---

## Data Flow Summary

```
Player Action (game.js)
        │
        ▼
Engine.recordStatistic() ──► MetricsCollector.record()
        │                           │
        │                           ▼
        │                   Batch storage (flush)
        │                           │
        ▼                           ▼
PerformanceTracker ◄─────── MetricsCollector.fetch()
        │                   
        ▼
   Reporter.getPerformanceReport()
        │
        ▼
   Aggregated/Formatted Report
```

